25	// Tune JOKER_PENALTY_FACTOR to scale all joker penalties up/down (1.0 = baseline).
26	const JOKER_PENALTY_FACTOR = 2.5;
27	const JOKER_IN_STOCK_PENALTY = 500 * JOKER_PENALTY_FACTOR; // already-owned joker: small "save it" cost
28	const JOKER_MOVE_COST_PENALTY = 3000 * JOKER_PENALTY_FACTOR; // buying with a move: must clearly outscore a normal swap
29	const JOKER_COIN_COST_FACTOR = 25 * JOKER_PENALTY_FACTOR; // per-coin score discount when buying with coins
30	const JOKER_COIN_BASE_PENALTY = 500 * JOKER_PENALTY_FACTOR; // flat component for coin buys
31	const SPECIAL_FREESWAP_PENALTY = 300;
32	const SPECIAL_TELEPORT_PENALTY = 500;
33	// Stacks on top of the joker penalty for hammer-on-blocked that doesn't complete a goal.
34	// Larger than the +10000 blocked-clear bonus so it loses to any normal match.
35	const HAMMER_ON_BLOCKED_NON_COMPLETING_PENALTY = 15000;
36	// When a joker move completes a level goal, we override the regular cost-based penalty
37	// with this minimal value so "use halver to finish" wins ties against normal matches.
38	const JOKER_GOAL_COMPLETING_PENALTY = 200;
