40	/**
41	 * Main entry point: finds the best move (any type) on the board.
42	 * Returns a move object whose shape includes a `type` field and per-type fields.
43	 * Back-compat shape: swap-like moves carry row1/col1/row2/col2/direction1/direction2/matchTiles.
44	 */
45	export function findBestSwap(game) {
46	    const candidates = findAllCandidateMoves(game);
47	    if (candidates.length === 0) return null;
48	
49	    const originalBoard = game.board;
50	    const originalIsUserSwap = game.isUserSwap;
51	    const originalLastSwapPosition = game.lastSwapPosition;
52	
53	    const evaluated = [];
54	    for (const move of candidates) {
55	        // Fresh working copy per evaluation so mutations don't leak.
56	        game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
57	        game.isUserSwap = false;
58	        game.lastSwapPosition = null;
59	        const result = evaluateMove(game, move);
60	        if (result !== null) evaluated.push(result);
61	    }
62	
63	    game.board = originalBoard;
64	    game.isUserSwap = originalIsUserSwap;
65	    game.lastSwapPosition = originalLastSwapPosition;
66	
67	    if (evaluated.length === 0) return null;
68	
69	    evaluated.sort((a, b) => {
70	        if (b.score !== a.score) return b.score - a.score;
71	        // Tiebreaker: prefer top-left.
72	        const aRow = a.row1 ?? a.row;
73	        const aCol = a.col1 ?? a.col;
74	        const bRow = b.row1 ?? b.row;
75	        const bCol = b.col1 ?? b.col;
76	        return aRow + aCol - (bRow + bCol);
77	    });
78	
79	    return evaluated[0];
80	}
